exercises.snippet:
class Num:
    def __init__(self, v):
        self.v = v
    def interpret(self):
        return self.v

class Add:
    def __init__(self, a, b):
        self.a = a
        self.b = b
    def interpret(self):
        return self.a.interpret() + self.b.interpret()

tree = Add(Num(3), Add(Num(4), Num(10)))
print(tree.interpret())

exercises.solution:
def interpret(node):
    if node['type'] == 'num':
        return node['value']
    if node['type'] == 'add':
        return interpret(node['left']) + interpret(node['right'])
    raise ValueError(node['type'])
